import 'package:firebase_database/firebase_database.dart'; import 'package:injectable/injectable.dart'; @injectable class FirebaseSignalingHelper { final _db = FirebaseDatabase.instance; Future<void> write(String path, Map<String, dynamic> data) => _db.ref(path).set(data); Future<void> delete(String path) => _db.ref(path).remove(); Stream<Map<String, dynamic>?> watch(String path) => _db.ref(path).onValue.map((e) { if (!e.snapshot.exists) return null; return Map<String, dynamic>.from(e.snapshot.value as Map); }); }